commits.content:
@import url('https://fonts.googleapis.com/css2?family=DM+Sans:ital,opsz,wght@0,9..40,400;0,9..40,500;0,9..40,600;0,9..40,700&display=swap');

* {
  box-sizing: border-box;
}

#root {
  width: 100%;
  max-width: none;
  margin: 0;
  padding: 0;
  text-align: left;
}

/* Loading Screen */
.loading-screen {
  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  background: linear-gradient(135deg, #1a1a2e 0%, #16213e 100%);
}

.loader {
  width: 40px;
  height: 40px;
  border: 3px solid rgba(255, 107, 107, 0.2);
  border-top-color: #FF6B6B;
  border-radius: 50%;
  animation: spin 1s linear infinite;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

/* Login Container */
.login-container {
  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  background: linear-gradient(135deg, #1a1a2e 0%, #16213e 50%, #0f0f1a 100%);
  position: relative;
  overflow: hidden;
}

.login-backdrop {
  position: absolute;
  inset: 0;
  background: 
    radial-gradient(circle at 20% 20%, rgba(255, 107, 107, 0.15) 0%, transparent 40%),
    radial-gradient(circle at 80% 80%, rgba(78, 205, 196, 0.15) 0%, transparent 40%),
    radial-gradient(circle at 50% 50%, rgba(255, 255, 255, 0.02) 0%, transparent 50%);
  pointer-events: none;
}

.login-card {
  position: relative;
  z-index: 1;
  background: rgba(255, 255, 255, 0.03);
  backdrop-filter: blur(20px);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 24px;
  padding: 48px 40px;
  width: 100%;
  max-width: 400px;
  margin: 20px;
  text-align: center;
  box-shadow: 
    0 24px 48px rgba(0, 0, 0, 0.4),
    inset 0 1px 0 rgba(255, 255, 255, 0.1);
  animation: cardFadeIn 0.6s ease-out;
}

@keyframes cardFadeIn {
  from {
    opacity: 0;
    transform: translateY(20px) scale(0.98);
  }
  to {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}

.login-logo {
  margin-bottom: 24px;
  animation: logoFloat 3s ease-in-out infinite;
}

@keyframes logoFloat {
  0%, 100% { transform: translateY(0); }
  50% { transform: translateY(-6px); }
}

.login-title {
  font-family: 'DM Sans', sans-serif;
  font-size: 2rem;
  font-weight: 700;
  margin: 0 0 8px 0;
  background: linear-gradient(135deg, #ffffff 0%, #a0a0a0 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.login-subtitle {
  font-family: 'DM Sans', sans-serif;
  font-size: 0.95rem;
  color: rgba(255, 255, 255, 0.5);
  margin: 0 0 32px 0;
}

.login-form {
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.password-input {
  font-family: 'DM Sans', sans-serif;
  font-size: 1rem;
  padding: 16px 20px;
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 12px;
  background: rgba(255, 255, 255, 0.05);
  color: #fff;
  outline: none;
  transition: all 0.3s ease;
}

.password-input::placeholder {
  color: rgba(255, 255, 255, 0.3);
}

.password-input:focus {
  border-color: rgba(255, 107, 107, 0.5);
  background: rgba(255, 255, 255, 0.08);
  box-shadow: 0 0 0 4px rgba(255, 107, 107, 0.1);
}

.error-message {
  font-family: 'DM Sans', sans-serif;
  font-size: 0.875rem;
  color: #FF6B6B;
  margin: 0;
  padding: 8px 12px;
  background: rgba(255, 107, 107, 0.1);
  border-radius: 8px;
  animation: shake 0.4s ease-in-out;
}

@keyframes shake {
  0%, 100% { transform: translateX(0); }
  25% { transform: translateX(-8px); }
  75% { transform: translateX(8px); }
}

.submit-button {
  font-family: 'DM Sans', sans-serif;
  font-size: 1rem;
  font-weight: 600;
  padding: 16px 32px;
  border: none;
  border-radius: 12px;
  background: linear-gradient(135deg, #FF6B6B 0%, #ee5a5a 100%);
  color: #fff;
  cursor: pointer;
  transition: all 0.3s ease;
  position: relative;
  overflow: hidden;
}

.submit-button::before {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(135deg, #4ECDC4 0%, #3dbdb5 100%);
  opacity: 0;
  transition: opacity 0.3s ease;
}

.submit-button:hover {
  transform: translateY(-2px);
  box-shadow: 0 12px 24px rgba(255, 107, 107, 0.3);
}

.submit-button:hover::before {
  opacity: 1;
}

.submit-button span,
.submit-button {
  position: relative;
  z-index: 1;
}

.submit-button:active {
  transform: translateY(0);
}

/* Main Page */
.page-container {
  min-height: 100vh;
  background: linear-gradient(180deg, #0f0f1a 0%, #1a1a2e 100%);
  display: flex;
  flex-direction: column;
}

/* Header */
.header {
  padding: 20px 40px;
  background: rgba(15, 15, 26, 0.8);
  backdrop-filter: blur(12px);
  border-bottom: 1px solid rgba(255, 255, 255, 0.05);
  position: sticky;
  top: 0;
  z-index: 100;
  animation: headerSlide 0.5s ease-out;
}

@keyframes headerSlide {
  from {
    opacity: 0;
    transform: translateY(-20px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.header-logo {
  display: flex;
  align-items: center;
  gap: 12px;
}

.logo-text {
  font-family: 'DM Sans', sans-serif;
  font-size: 1.25rem;
  font-weight: 700;
  background: linear-gradient(135deg, #ffffff 0%, #a0a0a0 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

/* Main Content */
.main-content {
  flex: 1;
  display: flex;
  flex-direction: column;
  padding: 0;
  animation: contentFadeIn 0.6s ease-out 0.2s backwards;
}

@keyframes contentFadeIn {
  from {
    opacity: 0;
    transform: translateY(20px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.intro-section {
  padding: 60px 40px 40px;
  max-width: 800px;
}

.page-title {
  font-family: 'DM Sans', sans-serif;
  font-size: 2.5rem;
  font-weight: 700;
  margin: 0 0 16px 0;
  background: linear-gradient(135deg, #ffffff 0%, #c0c0c0 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  line-height: 1.2;
}

.intro-text {
  font-family: 'DM Sans', sans-serif;
  font-size: 1.125rem;
  line-height: 1.7;
  color: rgba(255, 255, 255, 0.6);
  margin: 0;
}

/* Tab Navigation */
.tab-navigation {
  display: flex;
  flex-wrap: wrap;
  gap: 12px;
  padding: 0 40px 32px;
}

.tab-pill {
  font-family: 'DM Sans', sans-serif;
  font-size: 0.8125rem;
  font-weight: 600;
  letter-spacing: 0.05em;
  padding: 12px 24px;
  border: 1px solid rgba(255, 255, 255, 0.12);
  border-radius: 100px;
  background: rgba(255, 255, 255, 0.03);
  color: rgba(255, 255, 255, 0.5);
  cursor: pointer;
  transition: all 0.25s ease;
  position: relative;
  overflow: hidden;
}

.tab-pill::before {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(135deg, #FF6B6B 0%, #4ECDC4 100%);
  opacity: 0;
  transition: opacity 0.25s ease;
  z-index: -1;
}

.tab-pill:hover {
  border-color: rgba(255, 255, 255, 0.25);
  color: rgba(255, 255, 255, 0.8);
  transform: translateY(-1px);
}

.tab-pill.active {
  border-color: transparent;
  color: #fff;
  background: linear-gradient(135deg, #FF6B6B 0%, #ee5a5a 100%);
  box-shadow: 0 4px 16px rgba(255, 107, 107, 0.3);
}

.tab-pill.active:hover {
  transform: translateY(-2px);
  box-shadow: 0 6px 20px rgba(255, 107, 107, 0.4);
}

/* Tab Description */
.tab-description {
  display: flex;
  align-items: center;
  gap: 16px;
  padding: 0 40px 32px;
  animation: fadeIn 0.3s ease-out;
}

@keyframes fadeIn {
  from {
    opacity: 0;
    transform: translateY(8px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.tab-logo {
  height: 24px;
  width: auto;
  flex-shrink: 0;
}

.tab-logo.roil-logo {
  height: 20px;
  filter: invert(1);
}

.tab-description-text {
  font-family: 'DM Sans', sans-serif;
  font-size: 1rem;
  line-height: 1.6;
  color: rgba(255, 255, 255, 0.7);
  margin: 0;
}

/* Figma Section */
.figma-section {
  flex: 1;
  padding: 0 40px 40px;
  display: flex;
  min-height: 700px;
}

.figma-embed {
  width: 100%;
  height: 100%;
  min-height: 700px;
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 16px;
  background: rgba(255, 255, 255, 0.02);
}

/* Responsive */
@media (max-width: 768px) {
  .header {
    padding: 16px 20px;
  }

  .intro-section {
    padding: 40px 20px 24px;
  }

  .page-title {
    font-size: 1.75rem;
  }

  .intro-text {
    font-size: 1rem;
  }

  .tab-navigation {
    padding: 0 20px 24px;
    gap: 8px;
  }

  .tab-pill {
    font-size: 0.75rem;
    padding: 10px 16px;
  }

  .tab-description {
    flex-direction: column;
    align-items: flex-start;
    gap: 12px;
    padding: 0 20px 24px;
  }

  .tab-description-text {
    font-size: 0.9375rem;
  }

  .figma-section {
    padding: 0 20px 20px;
    min-height: 500px;
  }

  .figma-embed {
    min-height: 500px;
  }

  .login-card {
    padding: 32px 24px;
  }
}
